    'chart.stratbt':'\uadf8\ub9bc 3 &mdash; \uc804\ub7b5 \ubd84\ud3ec &mdash; BT','chart.stratgl':'\uadf8\ub9bc 4 &mdash; \uc804\ub7b5 \ubd84\ud3ec &mdash; GL',
